arguments.file_text:
@page "/catalog"
@using sv_b45041962a0145b29cf7202d8894bc68.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>Something went wrong: @_error</p>
        <button @onclick="LoadDataAsync">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogSidebar Categories="_categories"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />

        <main class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="_pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="catalog-loading">
                    <p>Loading products…</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _pageSize = 12;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _error = null;
            _loading = true;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            var result = await searchTask;

            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _error = null;
            _loading = true;

            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);

            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

/* Sidebar */
.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    background: #fafafa;
    align-self: flex-start;
}

.catalog-sidebar h2 {
    margin-top: 0;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h3 {
    font-size: 0.95rem;
    margin-bottom: 0.5rem;
}

.checkbox-label {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 0.75rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
}

.price-inputs input {
    width: 90px;
    padding: 0.3rem 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply,
.btn-clear {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-apply {
    background: #0d6efd;
    color: #fff;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    background: #e9ecef;
    color: #333;
}

.btn-clear:hover {
    background: #dee2e6;
}

/* Main content */
.catalog-main {
    flex: 1;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #e0e0e0;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.results-summary {
    color: #666;
    font-size: 0.9rem;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

/* Product card */
.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.12);
}

.product-image {
    height: 160px;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #888;
    font-size: 0.9rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.3rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: 600;
    color: #0d6efd;
}

.product-rating {
    color: #f5a623;
    margin-bottom: 0.4rem;
    font-size: 1.1rem;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: #fff;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    padding: 0.45rem;
    border: none;
    border-radius: 4px;
    background: #198754;
    color: #fff;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-add-to-cart:hover:not(:disabled) {
    background: #157347;
}

.btn-add-to-cart:disabled {
    background: #ccc;
    cursor: not-allowed;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    justify-content: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    padding: 1rem 0;
}

.btn-page {
    padding: 0.4rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-page:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-page:disabled {
    color: #adb5bd;
    cursor: not-allowed;
}

/* States */
.catalog-loading,
.empty-results {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 200px;
    color: #666;
}

.catalog-error {
    padding: 1.5rem;
    background: #fff3cd;
    border: 1px solid #ffc107;
    border-radius: 8px;
    text-align: center;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: none;
    border-radius: 4px;
    background: #0d6efd;
    color: #fff;
    cursor: pointer;
}

