+    public EventCallback<Product> OnAddToCart { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadDataAsync();
+    }
+
+    private async Task LoadDataAsync()
+    {
+        try
+        {
+            _error = null;
+            _loading = true;
+
+            var categoriesTask = ProductService.GetCategoriesAsync();
+            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
+
+            await Task.WhenAll(categoriesTask, searchTask);
+
+            _categories = await categoriesTask;
+            var result = await searchTask;
+
+            _products = result.Items;
+            _totalCount = result.TotalCount;
+            _totalPages = (int)Math.Ceiling((double)result.TotalCount / _pageSize);
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task SearchAsync()
+    {
+        try
+        {
+            _error = null;
+            _loading = true;
+
+            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
+
+            _products = result.Items;
+            _totalCount = result.TotalCount;
+            _totalPages = (int)Math.Ceiling((double)result.TotalCount / _pageSize);
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task HandleFiltersApplied(ProductFilter filter)
+    {
+        _filter = filter;
+        _currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandleFiltersCleared()
+    {
+        _filter = new ProductFilter(null, null, null, false);
+        _currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandleSortChanged(string sortBy)
+    {
+        _sortBy = sortBy;
+        _currentPage = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        _currentPage = page;
+        await SearchAsync();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        await OnAddToCart.InvokeAsync(product);
+    }
+}
